"use strict";
(function (global) {
  function runThemeCustomizerInit() {
    if (
      global.BioTernThemeRuntime &&
      typeof global.BioTernThemeRuntime.cleanupLegacyCustomizer === "function"
    ) {
      global.BioTernThemeRuntime.cleanupLegacyCustomizer();
    }
  }

  if (
    global.BioTernRuntimeBoot &&
    typeof global.BioTernRuntimeBoot.boot === "function"
  ) {
    global.BioTernRuntimeBoot.boot({
      name: "theme-customizer init",
      run: runThemeCustomizerInit,
    });
    return;
  }

  try {
    runThemeCustomizerInit();
  } catch (e) {}
})(window);
